def assess(record: dict) -> str:
    required_fields = {"case_id", "trace_id", "spans", "versions", "pii_in_trace"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (not record["trace_id"] or record["pii_in_trace"])
    return "PASS" if ok else "REDACT_AND_QUARANTINE_TRACE"

valid = {"case_id": "CASO-MOQ-051-1A", **{"trace_id": "tr-moq-51", "spans": {"answer", "prompt", "retrieval", "tool"}, "versions": {"prompt": "p3", "model": "m2", "index": "i4"}, "pii_in_trace": False}}
invalid = {"case_id": "CASO-MOQ-051-1A", **{"trace_id": "", "spans": {"answer", "prompt", "retrieval", "tool"}, "versions": {"prompt": "p3", "model": "m2", "index": "i4"}, "pii_in_trace": False}}
incomplete = dict(valid)
if "pii_in_trace" in incomplete:
    del incomplete["pii_in_trace"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

